# installe qu'UN (celui de son OS). Donc : protégé dès qu'UN correctif est présent.
$kbCorrecifs = @("KB5062557", "KB5062572", "KB5062554", "KB5062552", "KB5062553", "KB5062570", "KB5062561", "KB5062560", "KB5062624", "KB5062618", "KB5062632", "KB5062619", "KB5062592", "KB5062597")
$Session  = New-Object -ComObject Microsoft.Update.Session
$Searcher = $Session.CreateUpdateSearcher()
$Updates  = $Searcher.Search("IsInstalled=1").Updates
$installes = $Updates | ForEach-Object { $_.KBArticleIDs } | ForEach-Object { "KB$_" }
$presents = $kbCorrecifs | Where-Object { $installes -contains $_ }
if ($presents.Count -gt 0) {
    Write-Host "✅ PROTÉGÉ   - CVE-2025-49686 : correctif présent ($($presents -join ', '))" -ForegroundColor Green
} else {
    Write-Host "⚠️  VULNÉRABLE - CVE-2025-49686 : aucun correctif installé (ou CVE non applicable à cet OS)" -ForegroundColor Red
}

